Test (v): Anomaly detection
Diagnostic-only test. Surfaces documents that are unusually short, unusually long, suspected duplicates, or that mark large year-on-year page drops within a series.


Show code
doc_anomalies &lt;- country_body |&gt;
  filter(n_pages &gt; 0) |&gt;
  mutate(
    too_short = n_pages &lt; 10,
    too_long  = n_pages &gt; 1000,
    text_hash = map_chr(text, function(pages) {
      if (length(pages) == 0) return("")
      first_pages &lt;- pages[seq_len(min(5, length(pages)))]
      digest::digest(paste(unlist(first_pages), collapse = ""))
    })
  )

duplicate_check &lt;- doc_anomalies |&gt;
  group_by(country, text_hash) |&gt;
  filter(n() &gt; 1, text_hash != "") |&gt;
  ungroup() |&gt;
  select(country, year, body, package_id, text_hash)

year_trends &lt;- country_body |&gt;
  filter(n_pages &gt; 0) |&gt;
  group_by(country, body, year) |&gt;
  summarize(total_pages = sum(n_pages), .groups = "drop") |&gt;
  group_by(country, body) |&gt;
  arrange(year, .by_group = TRUE) |&gt;
  mutate(
    yoy_change  = (total_pages - lag(total_pages)) / lag(total_pages),
    sudden_drop = !is.na(yoy_change) & yoy_change &lt; -0.5
  ) |&gt;
  ungroup()

anomaly_summary &lt;- doc_anomalies |&gt;
  group_by(country) |&gt;
  summarize(
    n_short = sum(too_short),
    n_long  = sum(too_long),
    .groups = "drop"
  ) |&gt;
  left_join(
    duplicate_check |&gt; count(country, name = "n_duplicates"),
    by = "country"
  ) |&gt;
  left_join(
    year_trends |&gt; filter(sudden_drop) |&gt; count(country, name = "n_sudden_drops"),
    by = "country"
  ) |&gt;
  mutate(
    across(c(n_duplicates, n_sudden_drops), ~ replace_na(.x, 0L)),
    status = "INFO"
  )

for (i in seq_len(nrow(anomaly_summary))) {
  r &lt;- anomaly_summary[i, ]
  record_result(
    r$country, "v", "Anomalies detected",
    sprintf("%d short / %d long / %d dup / %d YoY drops",
            r$n_short, r$n_long, r$n_duplicates, r$n_sudden_drops),
    "Manual review", "INFO"
  )
}




